const allInvoices = $('Extract from File').all();
const existingInvoiceNumbers = $input.all().map(item => item.json.title);

// Convertir l'array en objet pour une recherche O(1)
const existingInvoicesMap = {};
existingInvoiceNumbers.forEach(invoiceNumber => {
  existingInvoicesMap[invoiceNumber] = true;
});

const nonImportedInvoices = allInvoices.filter(item => {
  return !existingInvoicesMap[item.json['Invoice number*']];
});

return nonImportedInvoices;

